import random

class SkipNode:
    def __init__(self, val, level):
        self.val = val
        self.next = [None] * (level + 1)

class SkipList:
    def __init__(self, max_level: int = 16, p: float = 0.5, seed: int = 42):
        self.max_level = max_level
        self.p = p
        self.level = 0
        self.rng = random.Random(seed)
        self.head = SkipNode(float('-inf'), max_level)
        self.tail = SkipNode(float('inf'), max_level)
        for i in range(max_level + 1):
            self.head.next[i] = self.tail

    def _random_level(self) -> int:
        lvl = 0
        while self.rng.random() < self.p and lvl < self.max_level:
            lvl += 1
        return lvl

    def insert(self, val: float) -> None:
        update = [None] * (self.max_level + 1)
        curr = self.head
        for i in range(self.level, -1, -1):
            while curr.next[i].val < val:
                curr = curr.next[i]
            update[i] = curr
        new_level = self._random_level()
        if new_level > self.level:
            for i in range(self.level + 1, new_level + 1):
                update[i] = self.head
            self.level = new_level
        new_node = SkipNode(val, new_level)
        for i in range(new_level + 1):
            new_node.next[i] = update[i].next[i]
            update[i].next[i] = new_node

    def search(self, val: float) -> bool:
        curr = self.head
        for i in range(self.level, -1, -1):
            while curr.next[i].val < val:
                curr = curr.next[i]
        curr = curr.next[0]
        return curr.val == val

    def delete(self, val: float) -> bool:
        update = [None] * (self.max_level + 1)
        curr = self.head
        for i in range(self.level, -1, -1):
            while curr.next[i].val < val:
                curr = curr.next[i]
            update[i] = curr
        target = curr.next[0]
        if target.val != val:
            return False
        for i in range(self.level + 1):
            if update[i].next[i] != target:
                break
            update[i].next[i] = target.next[i]
        while self.level > 0 and self.head.next[self.level] == self.tail:
            self.level -= 1
        return True
